    if (key === "__wake-reconcile") {
      // deferred onStart convergence (COMPAT-REPORT #34): alarms run with the
      // input gate open, so pending work can spawn + call back freely here.
      await this.#requestReconcile();
      return;
    }
    const handlers = this.#handlers.get(key);
    // await the handler: onFire/onStatus may themselves await a method prop (a
    // cross-DO round-trip), so the dispatcher must not resolve until that
    // in-flight capability call settles — otherwise the firing DO's I/O context
    // could tear down mid-flight (COMPAT-REPORT #22).
    if (key.startsWith("sensor:")) {
      const status = await probeStatus(String(this.#configs.get(key)?.url ?? ""));
      await handlers?.onStatus?.(status, Date.now());
    } else {
      await handlers?.onFire?.(Date.now());
    }
    if (this.#needsReconcile) await this.#requestReconcile();
    if (payload.rearm) await this.schedule(payload.rearm, "onAgentEvent", payload);
