export class LayoutReviewerDurable extends FiberAgentBase<ChildRuntimeState & Record<string, unknown>> {
  initialState = { ...LayoutReviewer.spec.initialState, __props: null, __callbacks: {} };
  protected selfBinding = "LAYOUT_REVIEWER" as const;
  protected childBinding = {}; // extend when this agent composes children

  async onStart() {}
  async onStateChanged(_state?: ChildRuntimeState & Record<string, unknown>, _source?: unknown) {}

  /** GENERATED: the parent's prop push. Receiving new props = re-render.
   *  Never work inline while the parent is still awaiting this adoption RPC —
   *  instead self-schedule an immediate gate-open alarm tick, so the child
   *  drives its own <task>/schedule work right after adoption completes.
   *  (An external POST /api/drive still works and is idempotent with this;
   *  COMPAT-REPORT #36.) */
  async setProps(props: Record<string, unknown>, callbacks: Record<string, CallbackRef>) {
    const st = this.state as ChildRuntimeState;
    if (
      JSON.stringify(st.__props) === JSON.stringify(props) &&
      JSON.stringify(st.__callbacks) === JSON.stringify(callbacks)
    ) {
      return;
    }
    this.setState({ ...this.state, __props: props, __callbacks: callbacks });
    await this.schedule(0, "onAgentEvent", { key: "__wake-reconcile" });
  }

  async shutdown() {
    for (const s of await this.getSchedules()) await this.cancelSchedule(s.id);
    this.setState({ ...this.state, __props: null, __children: [] });
  }

  async onRequest(req: Request): Promise<Response> {
    const path = new URL(req.url).pathname;
    if (path.endsWith("/api/drive") && req.method === "POST") {
      await this.reconcile();
      return Response.json({ ok: true, state: this.state }, { headers: { "cache-control": "no-store" } });
    }
    if (path.endsWith("/api/state") && req.method === "GET") {
      return Response.json({ state: this.state }, { headers: { "cache-control": "no-store" } });
    }
    return Response.json({ error: "not found" }, { status: 404, headers: { "cache-control": "no-store" } });
  }

  protected renderTree(state: ChildRuntimeState & Record<string, unknown>): unknown {
    if (!state.__props) return null; // not adopted by a parent yet
    // callbacks arrive as refs; impl sees ordinary functions. A method prop is
    // a capability WITH a return value: the proxy RETURNS the parent
    // dispatcher's result, so awaiting props.lookupRunbook(x) in the child
    // resolves to whatever the parent's freshest closure computed. Fire-and-forget
    // events (onResult) just ignore the resolved undefined. The reserved
    // `__emit` callback is the child's continuation output channel — routed to
    // `emit` below, it lands in the parent's __outputs and drives the parent's
    // render-prop continuation.
    const proxied: Record<string, (...args: unknown[]) => Promise<unknown>> = {};
    for (const [event, ref] of Object.entries(state.__callbacks)) {
      proxied[event] = async (...args) => {
        const ns = this.env[ref.binding] as unknown as DurableObjectNamespace;
        const parent = (ref.parentName
          ? await getAgentByName(ns as never, ref.parentName)
          : ns.get(ns.idFromString(ref.parentId))) as unknown as {
          onAgentEvent(p: { callback: { child: string; event: string }; args: unknown[] }): Promise<unknown>;
        };
        return await parent.onAgentEvent({ callback: { child: ref.child, event: ref.event }, args });
      };
    }
    return LayoutReviewer.spec.impl({ ...state.__props, ...proxied, emit: proxied.__emit ?? (() => {}), store: this.boundStore() } as never);
  }

  protected imperativePrompt(state: ChildRuntimeState & Record<string, unknown>): string {
    return LayoutReviewer.spec.getPrompt?.(state as never) ?? "";
  }
}

